const runId = $input.first().json.runId;
const samples = $input.first().json.samples || [];

// Combine sample texts (truncate each to 4000 chars to stay within context limits)
const combinedSampleText = samples
  .map((s, i) => `--- SAMPLE DOCUMENT ${i + 1}: ${s.sampleId} ---\n${(s.plainText || '').substring(0, 4000)}`)
  .join('\n\n');

console.log(`[WF04][${runId}] Preparing blueprint prompt. Samples: ${samples.length}, Total chars: ${combinedSampleText.length}`);

return [{
  json: {
    runId,
    source: $input.first().json.source,
    samples: $input.first().json.samples,
    options: $input.first().json.options,
    quality: $input.first().json.quality,
    blueprintPrompt: `You are a senior enterprise document analyst.

Analyze the following sample Business Requirements Document(s) and return a structured blueprint in JSON format.

Extract:
1. canonicalSections — the ordered list of section names as they appear
2. tone — the writing tone (formal_consulting, technical, executive, etc.)
3. verbosity — section length style (brief, medium, detailed)
4. tableUsage — true/false
5. bulletsPreferred — true/false
6. subsectionPatterns — any notable subsection patterns per main section
7. terminologyStyle — domain-specific vocabulary observed
8. documentType — BRD, FRD, SRS, etc.

IMPORTANT: Return only valid JSON. Do not include markdown fences or prose.

SAMPLE DOCUMENTS:
${combinedSampleText}

Return format:
{
  "documentType": "string",
  "canonicalSections": ["string"],
  "styleRules": {
    "tone": "string",
    "verbosity": "string",
    "tableUsage": boolean,
    "bulletsPreferred": boolean
  },
  "subsectionPatterns": { "SectionName": ["subsection1", "subsection2"] },
  "terminologyStyle": ["string"]
}`
  }
}];

const runId = $('Prepare Blueprint Prompt').first().json.runId;
const rawResponse = $input.first().json.text || $input.first().json.content || '';

console.log(`[WF04][${runId}] Parsing blueprint response...`);

let blueprint;
try {
  // Strip markdown fences if present
  const clean = rawResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  blueprint = JSON.parse(clean);
} catch (e) {
  console.warn(`[WF04][${runId}] Blueprint JSON parse failed, using default blueprint`);
  blueprint = {
    documentType: 'BRD',
    canonicalSections: [
      'Executive Summary', 'Business Need', 'Scope', 'Stakeholders',
      'Functional Requirements', 'Non-Functional Requirements',
      'Integrations', 'Assumptions', 'Risks', 'Dependencies',
      'Acceptance Criteria', 'Appendices'
    ],
    styleRules: {
      tone: 'formal_consulting',
      verbosity: 'medium',
      tableUsage: true,
      bulletsPreferred: true
    },
    subsectionPatterns: {},
    terminologyStyle: []
  };
}

return [{
  json: {
    runId,
    source: $('Prepare Blueprint Prompt').first().json.source,
    samples: $('Prepare Blueprint Prompt').first().json.samples,
    options: $('Prepare Blueprint Prompt').first().json.options,
    quality: $('Prepare Blueprint Prompt').first().json.quality,
    blueprint
  }
}];
